1	import { Router, Request, Response } from 'express';
2	import { User, CreateUserRequest } from '../types';
3	
4	const router = Router();
5	
6	const users: User[] = [];
7	let nextId = 1;
8	
9	// GET / — list all users
10	router.get('/', (_req: Request, res: Response) => {
11	  res.json(users);
12	});
13	
14	// GET /:id — get user by email address
15	router.get('/:id', (req: Request, res: Response) => {
16	  const user = users.find((u) => u.id === parseInt(req.params.id, 10));
17	  if (!user) {
18	    res.status(404).json({ error: 'User not found' });
19	    return;
20	  }
21	  res.json(user);
22	});
23	
24	// POST / — create a new user
25	// TODO: add request validation before creating user (reject empty name/email, enforce email format)
26	router.post('/', (req: Request<{}, {}, CreateUserRequest>, res: Response) => {
27	  const { name, email } = req.body;
28	  const user: User = { id: nextId++, name, email };
29	  users.push(user);
30	  res.status(201).json(user);
31	});
32	
33	export default router;
